/**
 * Webhook notification adapter.
 *
 * Implements NotificationAdapter for the 'webhook' channel with:
 * - JSON payload formatting from NotificationPayload
 * - Webhook URL validation
 * - Configurable HTTP transport (injectable for testing)
 * - Retry-friendly error handling (never throws, returns success/failure)
 */

import type { NotificationAdapter, AdapterSendResult } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A recorded webhook delivery for inspection in tests and debugging.
 */
export interface SentWebhook {
  url: string;
  payload: WebhookPayloadBody;
  sentAt: Date;
}

/**
 * The JSON body POSTed to the webhook URL.
 */
export interface WebhookPayloadBody {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookAdapterConfig {
  /** Timeout in milliseconds for webhook HTTP requests */
  timeoutMs: number;
  /** Custom headers to include in every webhook request */
  headers: Record<string, string>;
}

/**
 * Transport interface for actually posting webhooks.
 * Inject a real HTTP implementation in production,
 * or use the default in-memory transport for testing.
 */
export interface WebhookTransport {
  post(options: {
    url: string;
    headers: Record<string, string>;
    body: string;
    timeoutMs: number;
  }): Promise<{ statusCode: number; responseBody?: string }>;
}

/**
 * Default in-memory transport that records webhook deliveries instead of sending them.
 * Used in development and testing.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private sent: SentWebhook[] = [];
  private nextId = 1;

  async post(options: {
    url: string;
    headers: Record<string, string>;
    body: string;
    timeoutMs: number;
  }): Promise<{ statusCode: number; responseBody?: string }> {
    const payload = JSON.parse(options.body) as WebhookPayloadBody;
    this.sent.push({
      url: options.url,
      payload,
      sentAt: new Date(),
    });
    return { statusCode: 200, responseBody: `{"id":"wh-${String(this.nextId++).padStart(4, '0')}"}` };
  }

  getSentWebhooks(): SentWebhook[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
    this.nextId = 1;
  }
}

const URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/;

const defaultConfig: WebhookAdapterConfig = {
  timeoutMs: 5000,
  headers: {
    'Content-Type': 'application/json',
  },
};

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private config: WebhookAdapterConfig;
  private transport: WebhookTransport;

  constructor(config?: Partial<WebhookAdapterConfig>, transport?: WebhookTransport) {
    this.config = {
      ...defaultConfig,
      ...config,
      headers: { ...defaultConfig.headers, ...config?.headers },
    };
    this.transport = transport ?? new InMemoryWebhookTransport();
  }

  async send(payload: NotificationPayload): Promise<AdapterSendResult> {
    // Validate webhook URL (recipient is the webhook URL)
    if (!this.isValidUrl(payload.recipient)) {
      this.logger.warn(`Invalid webhook URL: ${payload.recipient}`);
      return {
        success: false,
        error: `Invalid webhook URL: ${payload.recipient}`,
      };
    }

    // Format the JSON payload
    const webhookBody = this.formatPayload(payload);
    const bodyJson = JSON.stringify(webhookBody);

    // POST via transport
    try {
      const result = await this.transport.post({
        url: payload.recipient,
        headers: this.config.headers,
        body: bodyJson,
        timeoutMs: this.config.timeoutMs,
      });

      if (result.statusCode >= 200 && result.statusCode < 300) {
        this.logger.info(`Webhook delivered to ${payload.recipient} (${result.statusCode})`);
        return {
          success: true,
          providerResponse: {
            statusCode: result.statusCode,
            responseBody: result.responseBody,
          },
        };
      }

      this.logger.warn(`Webhook delivery failed: ${payload.recipient} responded with ${result.statusCode}`);
      return {
        success: false,
        error: `Webhook returned status ${result.statusCode}`,
        providerResponse: {
          statusCode: result.statusCode,
          responseBody: result.responseBody,
        },
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Failed to deliver webhook to ${payload.recipient}: ${message}`);
      return {
        success: false,
        error: message,
      };
    }
  }

  /**
   * Format the notification payload into the webhook JSON body.
   */
  formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      event: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Validate a webhook URL.
   */
  isValidUrl(url: string): boolean {
    return URL_REGEX.test(url);
  }

  /**
   * Get all webhooks sent through this adapter (only works with InMemoryWebhookTransport).
   */
  getSentWebhooks(): SentWebhook[] {
    if (this.transport instanceof InMemoryWebhookTransport) {
      return this.transport.getSentWebhooks();
    }
    return [];
  }

  /**
   * Clear recorded webhooks (only works with InMemoryWebhookTransport).
   */
  clearSentWebhooks(): void {
    if (this.transport instanceof InMemoryWebhookTransport) {
      this.transport.clear();
    }
  }
}

