import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type { WebhookTransport } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmed',
    body: 'Your order #123 has been confirmed.',
    channel: 'webhook',
    type: 'order-confirmation',
    priority: 'normal',
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter(undefined, transport);
  });

  describe('send', () => {
    it('should deliver a webhook successfully', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerResponse?.statusCode).toBe(200);
    });

    it('should record webhooks via InMemoryWebhookTransport', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentWebhooks();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.url).toBe('https://hooks.example.com/notify');
      expect(sent[0]?.payload.event).toBe('order-confirmation');
      expect(sent[0]?.payload.subject).toBe('Order Confirmed');
    });

    it('should reject invalid webhook URLs', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-url' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should reject empty URLs', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should handle transport errors without throwing', async () => {
      const failingTransport: WebhookTransport = {
        async post() {
          throw new Error('Connection refused');
        },
      };
      const failAdapter = new WebhookAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });

    it('should handle non-Error transport exceptions', async () => {
      const failingTransport: WebhookTransport = {
        async post() {
          throw 'string error';
        },
      };
      const failAdapter = new WebhookAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown transport error');
    });

    it('should treat non-2xx status codes as failures', async () => {
      const badTransport: WebhookTransport = {
        async post() {
          return { statusCode: 500, responseBody: 'Internal Server Error' };
        },
      };
      const badAdapter = new WebhookAdapter(undefined, badTransport);

      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('status 500');
      expect(result.providerResponse?.statusCode).toBe(500);
    });

    it('should treat 201 as success', async () => {
      const createdTransport: WebhookTransport = {
        async post() {
          return { statusCode: 201 };
        },
      };
      const successAdapter = new WebhookAdapter(undefined, createdTransport);

      const result = await successAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerResponse?.statusCode).toBe(201);
    });

    it('should include metadata in the webhook payload', async () => {
      await adapter.send(makePayload({ metadata: { orderId: '456' } }));

      const sent = adapter.getSentWebhooks();
      expect(sent[0]?.payload.metadata).toEqual({ orderId: '456' });
    });
  });

  describe('URL validation', () => {
    it.each([
      'https://hooks.example.com/notify',
      'http://localhost:3000/webhook',
      'https://api.slack.com/hooks/T123/B456',
    ])('should accept valid URL: %s', (url) => {
      expect(adapter.isValidUrl(url)).toBe(true);
    });

    it.each([
      '',
      'not-a-url',
      'ftp://files.example.com',
      '://missing-scheme.com',
      'http://',
    ])('should reject invalid URL: "%s"', (url) => {
      expect(adapter.isValidUrl(url)).toBe(false);
    });
  });

  describe('payload formatting', () => {
    it('should format notification payload as webhook JSON', () => {
      const payload = makePayload();
      const formatted = adapter.formatPayload(payload);

      expect(formatted.event).toBe('order-confirmation');
      expect(formatted.recipient).toBe('https://hooks.example.com/notify');
      expect(formatted.subject).toBe('Order Confirmed');
      expect(formatted.body).toBe('Your order #123 has been confirmed.');
      expect(formatted.priority).toBe('normal');
      expect(formatted.timestamp).toBeDefined();
    });

    it('should include metadata when present', () => {
      const formatted = adapter.formatPayload(makePayload({
        metadata: { key: 'value' },
      }));

      expect(formatted.metadata).toEqual({ key: 'value' });
    });

    it('should leave metadata undefined when not present', () => {
      const formatted = adapter.formatPayload(makePayload());

      expect(formatted.metadata).toBeUndefined();
    });
  });

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      // Default adapter works without config
      const defaultAdapter = new WebhookAdapter(undefined, transport);
      expect(defaultAdapter.channel).toBe('webhook');
    });

    it('should merge custom headers with defaults', async () => {
      let capturedHeaders: Record<string, string> = {};
      const capturingTransport: WebhookTransport = {
        async post(options) {
          capturedHeaders = options.headers;
          return { statusCode: 200 };
        },
      };

      const customAdapter = new WebhookAdapter(
        { headers: { 'X-Webhook-Secret': 'secret123' } },
        capturingTransport,
      );
      await customAdapter.send(makePayload());

      expect(capturedHeaders['Content-Type']).toBe('application/json');
      expect(capturedHeaders['X-Webhook-Secret']).toBe('secret123');
    });

    it('should pass custom timeout to transport', async () => {
      let capturedTimeout = 0;
      const capturingTransport: WebhookTransport = {
        async post(options) {
          capturedTimeout = options.timeoutMs;
          return { statusCode: 200 };
        },
      };

      const customAdapter = new WebhookAdapter(
        { timeoutMs: 10000 },
        capturingTransport,
      );
      await customAdapter.send(makePayload());

      expect(capturedTimeout).toBe(10000);
    });
  });

  describe('getSentWebhooks / clearSentWebhooks', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentWebhooks()).toEqual([]);
    });

    it('should clear sent webhooks', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentWebhooks()).toHaveLength(1);

      adapter.clearSentWebhooks();
      expect(adapter.getSentWebhooks()).toEqual([]);
    });

    it('should return empty array when using non-InMemory transport', () => {
      const customAdapter = new WebhookAdapter(undefined, {
        async post() {
          return { statusCode: 200 };
        },
      });
      expect(customAdapter.getSentWebhooks()).toEqual([]);
    });
  });

  describe('channel property', () => {
    it('should be webhook', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });
});

describe('InMemoryWebhookTransport', () => {
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
  });

  it('should record sent webhooks', async () => {
    await transport.post({
      url: 'https://hooks.example.com/test',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ event: 'test', recipient: 'url', subject: 's', body: 'b', priority: 'normal', timestamp: new Date().toISOString() }),
      timeoutMs: 5000,
    });

    const sent = transport.getSentWebhooks();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.url).toBe('https://hooks.example.com/test');
    expect(sent[0]?.payload.event).toBe('test');
  });

  it('should clear all webhooks', async () => {
    await transport.post({
      url: 'https://hooks.example.com/test',
      headers: {},
      body: JSON.stringify({ event: 'test', recipient: 'url', subject: 's', body: 'b', priority: 'normal', timestamp: new Date().toISOString() }),
      timeoutMs: 5000,
    });
    transport.clear();
    expect(transport.getSentWebhooks()).toEqual([]);
  });

  it('should generate sequential webhook IDs', async () => {
    const r1 = await transport.post({
      url: 'https://a.com', headers: {}, body: JSON.stringify({ event: 'a', recipient: 'r', subject: 's', body: 'b', priority: 'normal', timestamp: '' }), timeoutMs: 1000,
    });
    const r2 = await transport.post({
      url: 'https://b.com', headers: {}, body: JSON.stringify({ event: 'b', recipient: 'r', subject: 's', body: 'b', priority: 'normal', timestamp: '' }), timeoutMs: 1000,
    });

    expect(r1.responseBody).toContain('wh-0001');
    expect(r2.responseBody).toContain('wh-0002');
  });

  it('should reset IDs on clear', async () => {
    await transport.post({
      url: 'https://a.com', headers: {}, body: JSON.stringify({ event: 'a', recipient: 'r', subject: 's', body: 'b', priority: 'normal', timestamp: '' }), timeoutMs: 1000,
    });
    transport.clear();
    const r = await transport.post({
      url: 'https://a.com', headers: {}, body: JSON.stringify({ event: 'a', recipient: 'r', subject: 's', body: 'b', priority: 'normal', timestamp: '' }), timeoutMs: 1000,
    });
    expect(r.responseBody).toContain('wh-0001');
  });
});

